#define MIN(a, b) ((a) <= (b) ? (a) : (b))

void dynproc_kernel(
    int arg0,
    const __global int* wall,
    const __global int* src_buf,
    __global int* dst_buf,
    int cols,
    int rows,
    int t_start,
    int borderCols,
    int theHalo,
    __local int* local_src,
    __local int* local_min,
    __global int* outputBuffer)
{
    int gid = get_global_id(0);
    int lid = get_local_id(0);
    int lsize = get_local_size(0);

    // Initialize local memory
    local_src[lid] = 0;
    local_min[lid] = 0;
    barrier(CLK_LOCAL_MEM_FENCE);

    if (gid >= cols) return;

    // We need to process 'arg0' rows starting from 't_start'.
    // The host swaps the buffers (src and dst) once before calling the kernel for a block of rows.
    // Inside the kernel, we must alternate which buffer we read from and write to for each row step.
    // Step 0: Read from src_buf (passed as src), Write to dst_buf (passed as dst).
    // Step 1: Read from dst_buf (just written), Write to src_buf (overwriting old src, which is now free).
    // Step 2: Read from src_buf (just written), Write to dst_buf.
    // And so on.

    const __global int* read_buf = src_buf;
    __global int* write_buf = dst_buf;

    for (int s = 0; s < arg0; s++) {
        int current_row = t_start + s;
        if (current_row >= rows - 1) break;

        // Compute min of neighbors in the current read buffer
        int val = read_buf[gid];
        int min_val = val;

        if (gid > 0) {
            int left = read_buf[gid - 1];
            if (left < min_val) min_val = left;
        }
        if (gid < cols - 1) {
            int right = read_buf[gid + 1];
            if (right < min_val) min_val = right;
        }

        // Write result to the wall position in the write buffer
        // Note: The original code stores results in dst[n] which corresponds to the current row being computed.
        // The wall array is accessed as wall[t+1][n]. Here current_row corresponds to t in the loop, so we access wall[current_row+1]?
        // Original loop: for (int t = 0; rows-1 > t; t++) ... dst[n] = wall[t+1][n] + min;
        // Here t_start is the starting t. So row index in wall is (t_start + s + 1).
        // However, the host passes 'wall' as data+cols (skipping row 0).
        // Let's check host init:
        // clEnqueueWriteBuffer(..., (data + cols), ...); // Skips row 0
        // So d_gpuWall[0] corresponds to wall[1][0].
        // In the kernel, wall index should be (current_row) if wall passed is shifted.
        // Original: wall[t+1][n]. If t=0, access wall[1].
        // Host passes data+cols. data[cols*n + j] is wall[n][j].
        // So data+cols starts at wall[1].
        // So wall_buffer_index = current_row (since t=0 -> wall[1] -> index 0 in passed buffer).
        // Wait, if t_start=0, s=0, current_row=0. We want wall[1].
        // Passed buffer starts at wall[1]. So index 0 is wall[1].
        // So index = current_row.

        int wall_idx = current_row * cols + gid;
        write_buf[gid] = wall[wall_idx] + min_val;

        // Ensure all writes for this row step are complete before next step reads
        barrier(CLK_GLOBAL_MEM_FENCE);

        // Swap buffers for the next iteration
        if (read_buf == src_buf) {
            read_buf = dst_buf;
            write_buf = src_buf;
        } else {
            read_buf = src_buf;
            write_buf = dst_buf;
        }
    }

    // Write a marker to outputBuffer to indicate completion (optional but safe)
    if (gid == 0) {
        outputBuffer[0] = 1;
    }
}
